local InMemoryCampaignState = (function()
local InMemoryCampaignState = {}

local REPRESENTATION_VIRTUAL = "VIRTUAL"
local TRANSITION_IDLE = "IDLE"
local MOVEMENT_NOT_STARTED = "NOT_STARTED"

local function copyArray(values)
  local result = {}
  for index, value in ipairs(values or {}) do
    result[index] = value
  end
  return result
end

function InMemoryCampaignState.new(config)
  local initialSlots = {}
  for slot = 1, config.template.expectedVehicleCount do
    initialSlots[#initialSlots + 1] = slot
  end

  local firstSection = config.zones.revealSections[config.virtualization.initialSectionIndex]
  if type(firstSection) ~= "table" then
    error("initial reveal section is unavailable")
  end
  if firstSection.entrySegmentIndex ~= 0 then
    error("initial reveal section must begin at global route start segment 0")
  end

  local entity = {
    entityId = config.scenarioId,
    representationState = REPRESENTATION_VIRTUAL,
    transitionState = TRANSITION_IDLE,
    movementState = MOVEMENT_NOT_STARTED,
    routeId = config.routeId,
    currentSectionIndex = config.virtualization.initialSectionIndex,
    -- segmentIndex identifies the authoritative current position on the global
    -- route: 0=start, 1..7=route anchors, 8=target.
    segmentIndex = firstSection.entrySegmentIndex,
    segmentProgress = 0,
    routeDistanceMeters = 0,
    configuredSpeedKph = config.virtualization.configuredSpeedKph,
    effectiveSpeedKph = config.virtualization.effectiveSpeedKph,
    lastMovementUpdateCampaignTime = timer.getTime(),
    lastStateChangeCampaignTime = timer.getTime(),
    survivingVehicleSlots = initialSlots,
    physicalGeneration = 0,
    runtimeGroupName = nil,
    revision = 0,
  }

  local campaignState = {
    entities = {
      [config.scenarioId] = entity,
    },
  }

  function campaignState:getEntity(entityId)
    return self.entities[entityId]
  end

  function campaignState:updateEntity(entityId, changes)
    local current = self.entities[entityId]
    if not current then
      error("unknown strategic entity: " .. tostring(entityId))
    end
    if type(changes) ~= "table" then
      error("entity changes must be a table")
    end

    for key, value in pairs(changes) do
      if key ~= "clearFields" then
        if key == "survivingVehicleSlots" then
          current[key] = copyArray(value)
        else
          current[key] = value
        end
      end
    end

    for _, key in ipairs(changes.clearFields or {}) do
      current[key] = nil
    end

    current.revision = current.revision + 1
    current.lastStateChangeCampaignTime = timer.getTime()
    return current
  end

  function campaignState:getEntitySnapshot(entityId)
    local current = self.entities[entityId]
    if not current then
      return nil
    end

    local snapshot = {}
    for key, value in pairs(current) do
      if key == "survivingVehicleSlots" then
        snapshot[key] = copyArray(value)
      else
        snapshot[key] = value
      end
    end
    return snapshot
  end

  return campaignState
end

return InMemoryCampaignState
end)()

local ConvoyCacheController = (function()
local ConvoyCacheController = {}

local REPRESENTATION_VIRTUAL = "VIRTUAL"
local REPRESENTATION_PHYSICAL = "PHYSICAL"

local TRANSITION_IDLE = "IDLE"
local TRANSITION_MATERIALIZING = "MATERIALIZING"
local TRANSITION_DEMATERIALIZING = "DEMATERIALIZING"

local MOVEMENT_NOT_STARTED = "NOT_STARTED"
local MOVEMENT_PHYSICAL_READY = "PHYSICAL_READY"
local MOVEMENT_PHYSICAL_MOVING = "PHYSICAL_MOVING"
local MOVEMENT_VIRTUAL_MOVING = "VIRTUAL_MOVING"
local MOVEMENT_ARRIVED = "ARRIVED"
local MOVEMENT_MATERIALIZATION_FAILED = "MATERIALIZATION_FAILED"
local MOVEMENT_DEMATERIALIZATION_FAILED = "DEMATERIALIZATION_FAILED"
local MOVEMENT_ROUTE_FAILED = "ROUTE_FAILED"
local MOVEMENT_DESTROYED = "DESTROYED"

local MOOSE_FORMATIONS = {
  ON_ROAD = "On Road",
}

local function displayValue(value)
  if value == nil then
    return "none"
  end
  return tostring(value)
end

local function copyArray(values)
  local copy = {}
  for index, value in ipairs(values or {}) do
    copy[index] = value
  end
  return copy
end

local function joinNumbers(values)
  local text = {}
  for index, value in ipairs(values or {}) do
    text[index] = tostring(value)
  end
  return table.concat(text, ",")
end

local function makeSet(values)
  local result = {}
  for _, value in ipairs(values or {}) do
    result[value] = true
  end
  return result
end

local function isInteger(value)
  return type(value) == "number" and value >= 0 and value == math.floor(value)
end

local function parseSpawnSlot(unitName)
  if type(unitName) ~= "string" then
    return nil
  end

  local suffix = string.match(unitName, "%-(%d+)$")
  if not suffix then
    return nil
  end

  return tonumber(suffix)
end

function ConvoyCacheController.new(options)
  local config = options.config
  local logger = options.logger
  local campaignState = options.campaignState

  if type(campaignState) ~= "table"
    or type(campaignState.getEntity) ~= "function"
    or type(campaignState.updateEntity) ~= "function"
    or type(campaignState.getEntitySnapshot) ~= "function" then
    error("a valid InMemoryCampaignState is required")
  end

  local entity = campaignState:getEntity(config.scenarioId)
  if type(entity) ~= "table" then
    error("CampaignState entity is unavailable: " .. tostring(config.scenarioId))
  end

  local controller = {
    campaignState = campaignState,
    entity = entity,
    spawner = nil,
    runtimeGroup = nil,
    routeAssignedGeneration = nil,
    retiredRuntimeGroupNames = {},
    pendingDematerialization = nil,
    arrivalLogged = false,
    lastError = nil,
  }

  local function updateEntity(changes)
    controller.entity = controller.campaignState:updateEntity(
      config.scenarioId,
      changes
    )
    return controller.entity
  end

  local function currentSection()
    return config.zones.revealSections[controller.entity.currentSectionIndex]
  end

  -- segmentIndex semantics are authoritative and stable:
  -- 0=start, 1..N=route anchors, N+1=target.
  local function finalSegmentIndex()
    return #config.zones.routeAnchors + 1
  end

  local function routePositionZoneNameAt(segmentIndex)
    if segmentIndex == 0 then
      return config.zones.start
    end
    if segmentIndex >= 1 and segmentIndex <= #config.zones.routeAnchors then
      return config.zones.routeAnchors[segmentIndex]
    end
    if segmentIndex == finalSegmentIndex() then
      return config.zones.target
    end
    return nil
  end

  local function commonFields()
    local section = currentSection()
    local pending = controller.pendingDematerialization
    return {
      entityId = controller.entity.entityId,
      routeId = controller.entity.routeId,
      representationState = controller.entity.representationState,
      transitionState = controller.entity.transitionState,
      movementState = controller.entity.movementState,
      currentSectionIndex = controller.entity.currentSectionIndex,
      currentSectionId = section and section.id or "none",
      segmentIndex = controller.entity.segmentIndex,
      segmentProgress = controller.entity.segmentProgress,
      routePositionZoneName = routePositionZoneNameAt(controller.entity.segmentIndex) or "none",
      physicalGeneration = controller.entity.physicalGeneration,
      revision = controller.entity.revision,
      runtimeGroupName = controller.entity.runtimeGroupName or "none",
      survivingVehicleSlots = joinNumbers(controller.entity.survivingVehicleSlots),
      pendingDematerialization = pending and true or false,
      pendingDestroyAttempts = pending and pending.attempts or 0,
    }
  end

  local function announce(text)
    options.announce(text)
  end

  local function reject(action, reason)
    local fields = commonFields()
    fields.action = action
    fields.reason = reason
    fields.missionTimeSeconds = timer.getTime()
    logger:info("convoy_cache_command_rejected", fields)
    announce(action .. " rejected: " .. reason)
    return false
  end

  local function logFailure(event, movementState, reason)
    controller.lastError = tostring(reason)
    updateEntity({
      movementState = movementState,
      transitionState = TRANSITION_IDLE,
    })
    local fields = commonFields()
    fields.reason = controller.lastError
    fields.missionTimeSeconds = timer.getTime()
    logger:error(event, fields)
    announce(event .. ": " .. controller.lastError)
    return false
  end

  local function logRecoverableDematerializationFailure(reason)
    controller.pendingDematerialization = nil
    controller.lastError = tostring(reason)
    updateEntity({
      movementState = MOVEMENT_PHYSICAL_MOVING,
      transitionState = TRANSITION_IDLE,
    })
    local fields = commonFields()
    fields.reason = controller.lastError
    fields.missionTimeSeconds = timer.getTime()
    logger:error("convoy_dematerialization_failed", fields)
    announce("Dematerialization failed: " .. controller.lastError)
    return false
  end

  local function ensureBootstrapReady(action)
    if options.getBootstrapOutcome() ~= "READY" then
      return reject(action, "bootstrap outcome is not READY")
    end
    return true
  end

  local function inspectGroup(group)
    return pcall(function()
      if type(group) ~= "table" then
        error("runtime group wrapper is unavailable")
      end

      return {
        name = group:GetName(),
        alive = group:IsAlive() == true,
        livingUnitCount = group:CountAliveUnits(),
      }
    end)
  end

  local function groupIsAlive(group)
    local ok, alive = pcall(function()
      return group and group:IsAlive() == true
    end)
    return ok and alive == true
  end

  local function nativeGroupExists(runtimeName)
    return pcall(function()
      local nativeGroup = Group.getByName(runtimeName)
      if not nativeGroup then
        return false
      end
      return nativeGroup:isExist() == true
    end)
  end

  local function validateRepresentationInvariant()
    if controller.entity.representationState == REPRESENTATION_VIRTUAL then
      if controller.entity.runtimeGroupName ~= nil then
        return false, "virtual entity still has an authoritative runtime group name"
      end
      if controller.runtimeGroup and groupIsAlive(controller.runtimeGroup) then
        return false, "virtual entity still has a live physical group"
      end
      return true
    end

    if controller.entity.representationState == REPRESENTATION_PHYSICAL then
      if controller.entity.transitionState == TRANSITION_DEMATERIALIZING then
        local pending = controller.pendingDematerialization
        if not pending then
          return false, "dematerializing entity has no pending transition record"
        end
        if pending.runtimeGroupName ~= controller.entity.runtimeGroupName then
          return false, "pending dematerialization runtime name does not match CampaignState"
        end
        return true
      end

      if not controller.runtimeGroup then
        return false, "physical entity has no runtime group wrapper"
      end
      if not groupIsAlive(controller.runtimeGroup) then
        return false, "physical entity runtime group is not alive"
      end
      return true
    end

    return false, "unknown representation state"
  end

  local function ensureRetiredGroupsAreNotAlive()
    for _, runtimeName in ipairs(controller.retiredRuntimeGroupNames) do
      local lookupOk, exists = nativeGroupExists(runtimeName)
      if not lookupOk then
        return false, exists
      end
      if exists then
        return false, "retired runtime group still exists: " .. runtimeName
      end
    end
    return true
  end

  local function captureSurvivingSlots(group)
    return pcall(function()
      local units = group:GetUnits()
      if type(units) ~= "table" then
        error("runtime group units are unavailable")
      end

      local slots = {}
      local seen = {}
      for _, unit in pairs(units) do
        if unit and unit:IsAlive() == true then
          local unitName = unit:GetName()
          local slot = parseSpawnSlot(unitName)
          if not slot then
            error("cannot parse vehicle slot from unit name: " .. displayValue(unitName))
          end
          if slot < 1 or slot > config.template.expectedVehicleCount then
            error("parsed vehicle slot is outside configured range: " .. tostring(slot))
          end
          if seen[slot] then
            error("duplicate vehicle slot detected: " .. tostring(slot))
          end
          seen[slot] = true
          slots[#slots + 1] = slot
        end
      end

      table.sort(slots)
      if #slots < 1 then
        error("no surviving vehicle slots remain")
      end

      local livingUnitCount = group:CountAliveUnits()
      if livingUnitCount ~= #slots then
        error(
          "living unit count does not match parsed slots: count="
            .. tostring(livingUnitCount) .. " slots=" .. tostring(#slots)
        )
      end

      return slots
    end)
  end

  local function pruneSpawnedGroupToSlots(group, survivingSlots)
    return pcall(function()
      local allowed = makeSet(survivingSlots)
      local observed = {}
      local units = group:GetUnits()
      if type(units) ~= "table" then
        error("spawned group units are unavailable")
      end

      for _, unit in pairs(units) do
        if unit and unit:IsAlive() == true then
          local unitName = unit:GetName()
          local slot = parseSpawnSlot(unitName)
          if not slot then
            error("cannot parse spawned vehicle slot from unit name: " .. displayValue(unitName))
          end

          if allowed[slot] then
            observed[slot] = true
          else
            unit:Destroy(false)
          end
        end
      end

      for _, slot in ipairs(survivingSlots) do
        if not observed[slot] then
          error("required surviving slot was not spawned: " .. tostring(slot))
        end
      end

      return #survivingSlots
    end)
  end

  local function resolveRoutePosition(segmentIndex)
    return pcall(function()
      if not isInteger(segmentIndex) or segmentIndex > finalSegmentIndex() then
        error("route position segment index is outside the configured route")
      end

      local zoneName = routePositionZoneNameAt(segmentIndex)
      if not zoneName then
        error("route position zone name is unavailable for segment " .. tostring(segmentIndex))
      end

      local zone = ZONE:FindByName(zoneName)
      if not zone then
        error("route position zone is unavailable: " .. tostring(zoneName))
      end

      local coordinate = zone:GetCoordinate()
      if not coordinate then
        error("route position coordinate is unavailable: " .. tostring(zoneName))
      end

      return {
        coordinate = coordinate,
        segmentIndex = segmentIndex,
        zone = zone,
        zoneName = zoneName,
      }
    end)
  end

  local function buildRemainingRoute(startSegmentIndex)
    return pcall(function()
      local formation = MOOSE_FORMATIONS[config.routing.formation]
      if config.routing.roadOnly ~= true or not formation then
        error("road-only ON_ROAD routing configuration is required")
      end

      local finalIndex = finalSegmentIndex()
      if not isInteger(startSegmentIndex)
        or startSegmentIndex < 1
        or startSegmentIndex > finalIndex then
        error("route slice start is outside the configured route")
      end

      local waypoints = {}
      local routeZoneNames = {}
      for segmentIndex = startSegmentIndex, finalIndex do
        local zoneName = routePositionZoneNameAt(segmentIndex)
        local zone = ZONE:FindByName(zoneName)
        if not zone then
          error("global route zone is unavailable: " .. tostring(zoneName))
        end
        local coordinate = zone:GetCoordinate()
        if not coordinate then
          error("global route coordinate is unavailable: " .. tostring(zoneName))
        end
        local waypoint = coordinate:WaypointGround(config.routing.speedKph, formation)
        if type(waypoint) ~= "table" then
          error("ground waypoint construction failed: " .. tostring(zoneName))
        end
        waypoints[#waypoints + 1] = waypoint
        routeZoneNames[#routeZoneNames + 1] = zoneName
      end

      if #waypoints < 1 then
        error("remaining physical route contains no waypoints")
      end

      return {
        waypoints = waypoints,
        routeZoneNames = routeZoneNames,
        startSegmentIndex = startSegmentIndex,
        endSegmentIndex = finalIndex,
      }
    end)
  end

  local function destroyGroupSilently(group)
    return pcall(function()
      group:Destroy(false)
    end)
  end

  local function finalizeDematerialization(pending)
    if controller.pendingDematerialization ~= pending then
      return false
    end

    controller.retiredRuntimeGroupNames[#controller.retiredRuntimeGroupNames + 1] = pending.runtimeGroupName
    controller.pendingDematerialization = nil
    controller.runtimeGroup = nil
    controller.spawner = nil
    controller.routeAssignedGeneration = nil
    controller.lastError = nil

    updateEntity({
      clearFields = { "runtimeGroupName" },
      representationState = REPRESENTATION_VIRTUAL,
      transitionState = TRANSITION_IDLE,
      movementState = MOVEMENT_VIRTUAL_MOVING,
    })

    local invariantOk, invariantError = validateRepresentationInvariant()
    local fields = commonFields()
    fields.exitZoneName = pending.exitZoneName
    fields.retiredRuntimeGroupName = pending.runtimeGroupName
    fields.destroyConfirmationAttempts = pending.attempts
    fields.destroyConfirmationSeconds = timer.getTime() - pending.startedAt
    fields.missionTimeSeconds = timer.getTime()
    fields.invariantOk = invariantOk
    if not invariantOk then
      fields.invariantError = invariantError
      logger:error("convoy_dematerialization_post_invariant_failed", fields)
      announce("Dematerialization completed with invariant failure: " .. tostring(invariantError))
      return false
    end

    logger:info("convoy_dematerialized", fields)
    announce(
      "Convoy dematerialized"
        .. "\nSection: " .. pending.sectionId
        .. "\nRetired group: " .. pending.runtimeGroupName
        .. "\nVehicle slots: " .. joinNumbers(controller.entity.survivingVehicleSlots)
    )
    return true
  end

  local function pollPendingDematerialization(_, scheduledTime)
    local pending = controller.pendingDematerialization
    if not pending then
      return nil
    end

    pending.attempts = pending.attempts + 1
    local lookupOk, existsOrError = nativeGroupExists(pending.runtimeGroupName)
    if lookupOk and existsOrError == false then
      finalizeDematerialization(pending)
      return nil
    end

    local elapsed = timer.getTime() - pending.startedAt
    if elapsed >= config.virtualization.destroyConfirmationTimeoutSeconds then
      local reason
      if lookupOk then
        reason = "native runtime group still exists after destruction timeout"
      else
        reason = "native destruction confirmation failed: " .. tostring(existsOrError)
      end
      logRecoverableDematerializationFailure(reason)
      return nil
    end

    local fields = commonFields()
    fields.elapsedSeconds = elapsed
    fields.runtimeGroupName = pending.runtimeGroupName
    fields.missionTimeSeconds = timer.getTime()
    if lookupOk then
      logger:info("convoy_dematerialization_confirmation_pending", fields)
    else
      fields.reason = existsOrError
      logger:error("convoy_dematerialization_confirmation_check_failed", fields)
    end

    return scheduledTime + config.virtualization.destroyConfirmationPollSeconds
  end

  function controller:materialize()
    local action = "Materialize convoy"
    local requestedFields = commonFields()
    requestedFields.action = action
    requestedFields.missionTimeSeconds = timer.getTime()
    logger:info("convoy_materialization_requested", requestedFields)

    if not ensureBootstrapReady(action) then
      return false
    end
    if self.entity.transitionState ~= TRANSITION_IDLE then
      return reject(action, "another representation transition is active")
    end
    if self.entity.representationState ~= REPRESENTATION_VIRTUAL then
      return reject(action, "entity is not virtual")
    end
    if self.runtimeGroup and groupIsAlive(self.runtimeGroup) then
      return reject(action, "a live runtime group already exists")
    end
    if self.entity.movementState == MOVEMENT_ARRIVED then
      return reject(action, "entity has already arrived")
    end

    local retiredOk, retiredError = ensureRetiredGroupsAreNotAlive()
    if not retiredOk then
      return logFailure(
        "convoy_materialization_failed",
        MOVEMENT_MATERIALIZATION_FAILED,
        retiredError
      )
    end

    local section = currentSection()
    if not section then
      return logFailure(
        "convoy_materialization_failed",
        MOVEMENT_MATERIALIZATION_FAILED,
        "current reveal section is unavailable"
      )
    end
    if self.entity.segmentIndex ~= section.entrySegmentIndex then
      return reject(
        action,
        "CampaignState route position does not match the current reveal-window entry"
      )
    end

    local positionOk, positionOrError = resolveRoutePosition(self.entity.segmentIndex)
    if not positionOk then
      return logFailure(
        "convoy_materialization_failed",
        MOVEMENT_MATERIALIZATION_FAILED,
        positionOrError
      )
    end

    updateEntity({ transitionState = TRANSITION_MATERIALIZING })
    local nextGeneration = self.entity.physicalGeneration + 1
    local alias = config.template.runtimeAliasPrefix
      .. "_G" .. string.format("%02d", nextGeneration)

    local constructionOk, spawnerOrError = pcall(function()
      local spawner = SPAWN:NewWithAlias(config.template.groupName, alias)
      return spawner:InitPositionCoordinate(positionOrError.coordinate)
    end)
    if not constructionOk or type(spawnerOrError) ~= "table" then
      return logFailure(
        "convoy_materialization_failed",
        MOVEMENT_MATERIALIZATION_FAILED,
        constructionOk and "SPAWN position initialization returned no spawner" or spawnerOrError
      )
    end

    local spawnOk, groupOrError = pcall(function()
      return spawnerOrError:Spawn()
    end)
    if not spawnOk or type(groupOrError) ~= "table" then
      return logFailure(
        "convoy_materialization_failed",
        MOVEMENT_MATERIALIZATION_FAILED,
        spawnOk and "SPAWN:Spawn did not return a GROUP wrapper" or groupOrError
      )
    end

    local runtimeGroup = groupOrError
    local pruneOk, livingUnitCount = pruneSpawnedGroupToSlots(
      runtimeGroup,
      self.entity.survivingVehicleSlots
    )
    if not pruneOk then
      destroyGroupSilently(runtimeGroup)
      return logFailure(
        "convoy_materialization_failed",
        MOVEMENT_MATERIALIZATION_FAILED,
        livingUnitCount
      )
    end

    local inspectionOk, inspection = inspectGroup(runtimeGroup)
    if not inspectionOk then
      destroyGroupSilently(runtimeGroup)
      return logFailure(
        "convoy_materialization_failed",
        MOVEMENT_MATERIALIZATION_FAILED,
        inspection
      )
    end
    if not inspection.alive then
      destroyGroupSilently(runtimeGroup)
      return logFailure(
        "convoy_materialization_failed",
        MOVEMENT_MATERIALIZATION_FAILED,
        "spawned runtime group is not alive"
      )
    end

    self.spawner = spawnerOrError
    self.runtimeGroup = runtimeGroup
    updateEntity({
      physicalGeneration = nextGeneration,
      runtimeGroupName = inspection.name,
      representationState = REPRESENTATION_PHYSICAL,
      transitionState = TRANSITION_IDLE,
      movementState = MOVEMENT_PHYSICAL_READY,
      segmentProgress = 0,
      lastMovementUpdateCampaignTime = timer.getTime(),
    })
    self.routeAssignedGeneration = nil
    self.lastError = nil

    local invariantOk, invariantError = validateRepresentationInvariant()
    if not invariantOk then
      destroyGroupSilently(runtimeGroup)
      self.runtimeGroup = nil
      self.spawner = nil
      updateEntity({
        clearFields = { "runtimeGroupName" },
        representationState = REPRESENTATION_VIRTUAL,
      })
      return logFailure(
        "convoy_materialization_failed",
        MOVEMENT_MATERIALIZATION_FAILED,
        invariantError
      )
    end

    local fields = commonFields()
    fields.materializationAnchorName = positionOrError.zoneName
    fields.revealEntryZoneName = section.entry
    fields.livingUnitCount = livingUnitCount
    fields.nextRouteSegmentIndex = self.entity.segmentIndex + 1
    fields.nextRouteZoneName = routePositionZoneNameAt(self.entity.segmentIndex + 1)
    fields.missionTimeSeconds = timer.getTime()
    logger:info("convoy_materialized", fields)
    announce(
      "Convoy materialized"
        .. "\nSection: " .. section.id
        .. "\nRoute anchor: " .. positionOrError.zoneName
        .. "\nReveal entry: " .. section.entry
        .. "\nRuntime group: " .. inspection.name
        .. "\nGeneration: " .. nextGeneration
        .. "\nVehicle slots: " .. joinNumbers(self.entity.survivingVehicleSlots)
    )
    return true
  end

  function controller:startPhysicalRoute()
    local action = "Start physical route"
    local fields = commonFields()
    fields.action = action
    fields.missionTimeSeconds = timer.getTime()
    logger:info("convoy_cached_route_requested", fields)

    if not ensureBootstrapReady(action) then
      return false
    end
    if self.entity.transitionState ~= TRANSITION_IDLE then
      return reject(action, "another representation transition is active")
    end
    if self.entity.representationState ~= REPRESENTATION_PHYSICAL then
      return reject(action, "entity is not physical")
    end
    if self.entity.movementState ~= MOVEMENT_PHYSICAL_READY then
      return reject(action, "physical representation is not ready for route assignment")
    end
    if self.routeAssignedGeneration == self.entity.physicalGeneration then
      return reject(action, "route is already assigned to this physical generation")
    end

    local invariantOk, invariantError = validateRepresentationInvariant()
    if not invariantOk then
      return logFailure("convoy_cached_route_failed", MOVEMENT_ROUTE_FAILED, invariantError)
    end

    local startSegmentIndex = self.entity.segmentIndex + 1
    local routeOk, routeOrError = buildRemainingRoute(startSegmentIndex)
    if not routeOk then
      return logFailure("convoy_cached_route_failed", MOVEMENT_ROUTE_FAILED, routeOrError)
    end

    local assignmentOk, assignmentResult = pcall(function()
      return self.runtimeGroup:Route(routeOrError.waypoints, 0)
    end)
    if not assignmentOk or not assignmentResult then
      return logFailure(
        "convoy_cached_route_failed",
        MOVEMENT_ROUTE_FAILED,
        assignmentOk and "route assignment returned nil" or assignmentResult
      )
    end

    self.routeAssignedGeneration = self.entity.physicalGeneration
    updateEntity({
      movementState = MOVEMENT_PHYSICAL_MOVING,
      lastMovementUpdateCampaignTime = timer.getTime(),
    })
    self.lastError = nil

    local section = currentSection()
    local successFields = commonFields()
    successFields.totalWaypointCount = #routeOrError.waypoints
    successFields.routeSliceStartSegmentIndex = routeOrError.startSegmentIndex
    successFields.routeSliceEndSegmentIndex = routeOrError.endSegmentIndex
    successFields.firstRouteZoneName = routeOrError.routeZoneNames[1]
    successFields.lastRouteZoneName = routeOrError.routeZoneNames[#routeOrError.routeZoneNames]
    successFields.missionTimeSeconds = timer.getTime()
    logger:info("convoy_cached_route_started", successFields)
    announce(
      "Physical route started"
        .. "\nSection: " .. section.id
        .. "\nGeneration: " .. self.entity.physicalGeneration
        .. "\nWaypoints: " .. #routeOrError.waypoints
        .. "\nFirst: " .. routeOrError.routeZoneNames[1]
        .. "\nLast: " .. routeOrError.routeZoneNames[#routeOrError.routeZoneNames]
    )
    return true
  end

  function controller:dematerialize()
    local action = "Dematerialize convoy"
    local fields = commonFields()
    fields.action = action
    fields.missionTimeSeconds = timer.getTime()
    logger:info("convoy_dematerialization_requested", fields)

    if not ensureBootstrapReady(action) then
      return false
    end
    if self.entity.transitionState ~= TRANSITION_IDLE then
      return reject(action, "another representation transition is active")
    end
    if self.entity.representationState ~= REPRESENTATION_PHYSICAL then
      return reject(action, "entity is not physical")
    end
    if self.entity.movementState ~= MOVEMENT_PHYSICAL_MOVING then
      return reject(action, "physical convoy is not moving on its assigned route")
    end

    local invariantOk, invariantError = validateRepresentationInvariant()
    if not invariantOk then
      return logFailure(
        "convoy_dematerialization_failed",
        MOVEMENT_DEMATERIALIZATION_FAILED,
        invariantError
      )
    end

    local section = currentSection()
    local lookupOk, exitZone = pcall(function()
      return ZONE:FindByName(section.exit)
    end)
    if not lookupOk or not exitZone then
      return logFailure(
        "convoy_dematerialization_failed",
        MOVEMENT_DEMATERIALIZATION_FAILED,
        lookupOk and "exit zone is unavailable: " .. section.exit or exitZone
      )
    end

    local membershipOk, insideExit = pcall(function()
      return self.runtimeGroup:IsCompletelyInZone(exitZone) == true
    end)
    if not membershipOk then
      return logFailure(
        "convoy_dematerialization_failed",
        MOVEMENT_DEMATERIALIZATION_FAILED,
        insideExit
      )
    end
    if not insideExit then
      return reject(action, "runtime group is not completely inside the current exit zone")
    end

    local slotsOk, survivingSlots = captureSurvivingSlots(self.runtimeGroup)
    if not slotsOk then
      return logFailure(
        "convoy_dematerialization_failed",
        MOVEMENT_DEMATERIALIZATION_FAILED,
        survivingSlots
      )
    end

    local pending = {
      runtimeGroupName = self.entity.runtimeGroupName,
      sectionId = section.id,
      exitZoneName = section.exit,
      startedAt = timer.getTime(),
      attempts = 0,
    }
    self.pendingDematerialization = pending

    updateEntity({
      transitionState = TRANSITION_DEMATERIALIZING,
      survivingVehicleSlots = copyArray(survivingSlots),
      segmentIndex = section.exitSegmentIndex,
      segmentProgress = 1,
      lastMovementUpdateCampaignTime = timer.getTime(),
    })

    local scheduleOk, scheduleResult = pcall(function()
      return timer.scheduleFunction(
        pollPendingDematerialization,
        nil,
        timer.getTime() + config.virtualization.destroyConfirmationPollSeconds
      )
    end)
    if not scheduleOk or scheduleResult == nil then
      return logRecoverableDematerializationFailure(
        scheduleOk and "destruction confirmation scheduler returned nil" or scheduleResult
      )
    end

    local destructionOk, destructionError = destroyGroupSilently(self.runtimeGroup)
    if not destructionOk then
      return logRecoverableDematerializationFailure(destructionError)
    end

    local successFields = commonFields()
    successFields.exitZoneName = section.exit
    successFields.destroyConfirmationScheduleId = scheduleResult
    successFields.destroyConfirmationPollSeconds = config.virtualization.destroyConfirmationPollSeconds
    successFields.destroyConfirmationTimeoutSeconds = config.virtualization.destroyConfirmationTimeoutSeconds
    successFields.missionTimeSeconds = timer.getTime()
    logger:info("convoy_dematerialization_confirmation_scheduled", successFields)
    announce(
      "Dematerialization started"
        .. "\nSection: " .. section.id
        .. "\nAwaiting native destruction confirmation"
    )
    return true
  end

  function controller:advanceVirtual()
    local action = "Advance virtual convoy"
    local fields = commonFields()
    fields.action = action
    fields.missionTimeSeconds = timer.getTime()
    logger:info("convoy_virtual_advance_requested", fields)

    if not ensureBootstrapReady(action) then
      return false
    end
    if self.entity.transitionState ~= TRANSITION_IDLE then
      return reject(action, "another representation transition is active")
    end
    if self.entity.representationState ~= REPRESENTATION_VIRTUAL then
      return reject(action, "entity is not virtual")
    end
    if self.entity.movementState ~= MOVEMENT_VIRTUAL_MOVING then
      return reject(action, "virtual entity is not moving")
    end
    if self.entity.currentSectionIndex >= config.virtualization.finalSectionIndex then
      return reject(action, "entity is already at the final reveal section")
    end

    local retiredOk, retiredError = ensureRetiredGroupsAreNotAlive()
    if not retiredOk then
      return logFailure(
        "convoy_virtual_advance_failed",
        MOVEMENT_DEMATERIALIZATION_FAILED,
        retiredError
      )
    end

    local nextSectionIndex = self.entity.currentSectionIndex + 1
    local section = config.zones.revealSections[nextSectionIndex]
    local positionZoneName = routePositionZoneNameAt(section.entrySegmentIndex)
    if not positionZoneName then
      return logFailure(
        "convoy_virtual_advance_failed",
        MOVEMENT_ROUTE_FAILED,
        "next reveal-window route position is unavailable"
      )
    end

    updateEntity({
      currentSectionIndex = nextSectionIndex,
      segmentIndex = section.entrySegmentIndex,
      segmentProgress = 0,
      lastMovementUpdateCampaignTime = timer.getTime(),
    })
    self.lastError = nil

    local successFields = commonFields()
    successFields.revealEntryZoneName = section.entry
    successFields.materializationAnchorName = positionZoneName
    successFields.nextRouteSegmentIndex = section.entrySegmentIndex + 1
    successFields.nextRouteZoneName = routePositionZoneNameAt(section.entrySegmentIndex + 1)
    successFields.missionTimeSeconds = timer.getTime()
    logger:info("convoy_virtual_advanced", successFields)
    announce(
      "Virtual convoy advanced"
        .. "\nNext section: " .. section.id
        .. "\nReveal entry: " .. section.entry
        .. "\nRoute anchor: " .. positionZoneName
        .. "\nNext route point: " .. displayValue(routePositionZoneNameAt(section.entrySegmentIndex + 1))
    )
    return true
  end

  function controller:showStatus()
    local section = currentSection()
    local inspectionError = nil
    local livingUnitCount = nil
    local targetZoneMembership = nil

    if self.entity.representationState == REPRESENTATION_PHYSICAL and self.runtimeGroup then
      local inspectionOk, inspection = inspectGroup(self.runtimeGroup)
      if inspectionOk then
        if inspection.name ~= self.entity.runtimeGroupName then
          updateEntity({ runtimeGroupName = inspection.name })
        end
        livingUnitCount = inspection.livingUnitCount
        if livingUnitCount < 1
          and self.entity.transitionState ~= TRANSITION_DEMATERIALIZING then
          updateEntity({ movementState = MOVEMENT_DESTROYED })
        end
      else
        inspectionError = inspection
      end

      if self.entity.currentSectionIndex == config.virtualization.finalSectionIndex
        and self.entity.transitionState == TRANSITION_IDLE
        and self.entity.movementState == MOVEMENT_PHYSICAL_MOVING then
        local targetLookupOk, targetZone = pcall(function()
          return ZONE:FindByName(config.zones.target)
        end)
        if targetLookupOk and targetZone then
          local membershipOk, membership = pcall(function()
            return self.runtimeGroup:IsCompletelyInZone(targetZone) == true
          end)
          if membershipOk then
            targetZoneMembership = membership
            if membership
              and self.routeAssignedGeneration == self.entity.physicalGeneration
              and self.entity.movementState ~= MOVEMENT_DESTROYED then
              updateEntity({
                movementState = MOVEMENT_ARRIVED,
                segmentIndex = finalSegmentIndex(),
                segmentProgress = 1,
                lastMovementUpdateCampaignTime = timer.getTime(),
              })
              if not self.arrivalLogged then
                self.arrivalLogged = true
                local arrivalFields = commonFields()
                arrivalFields.livingUnitCount = livingUnitCount
                arrivalFields.targetZoneMembership = true
                arrivalFields.targetZoneName = config.zones.target
                arrivalFields.missionTimeSeconds = timer.getTime()
                logger:info("convoy_route_arrived", arrivalFields)
              end
            end
          else
            inspectionError = membership
          end
        elseif not targetLookupOk then
          inspectionError = targetZone
        else
          inspectionError = "target zone is unavailable"
        end
      end
    end

    local invariantOk, invariantError = validateRepresentationInvariant()
    local fields = commonFields()
    fields.livingUnitCount = livingUnitCount or "unavailable"
    fields.targetZoneMembership = targetZoneMembership == nil
      and "unavailable" or targetZoneMembership
    fields.invariantOk = invariantOk
    fields.missionTimeSeconds = timer.getTime()
    if self.pendingDematerialization then
      fields.pendingDestroyElapsedSeconds = timer.getTime()
        - self.pendingDematerialization.startedAt
      fields.pendingDestroyRuntimeGroupName = self.pendingDematerialization.runtimeGroupName
    end
    if not invariantOk then
      fields.invariantError = invariantError
    end
    if inspectionError then
      fields.inspectionError = inspectionError
    end
    if self.lastError then
      fields.lastError = self.lastError
    end
    logger:info("convoy_cache_status", fields)

    announce(
      "Entity: " .. self.entity.entityId
        .. "\nRepresentation: " .. self.entity.representationState
        .. "\nTransition: " .. self.entity.transitionState
        .. "\nMovement: " .. self.entity.movementState
        .. "\nSection: " .. displayValue(section and section.id)
        .. "\nSegment: " .. tostring(self.entity.segmentIndex)
        .. "\nRoute position: " .. displayValue(routePositionZoneNameAt(self.entity.segmentIndex))
        .. "\nGeneration: " .. self.entity.physicalGeneration
        .. "\nRuntime group: " .. displayValue(self.entity.runtimeGroupName)
        .. "\nVehicle slots: " .. joinNumbers(self.entity.survivingVehicleSlots)
        .. "\nPending destroy: " .. tostring(self.pendingDematerialization ~= nil)
        .. "\nInvariant: " .. tostring(invariantOk)
    )
  end

  function controller:getState()
    return self.campaignState:getEntitySnapshot(config.scenarioId)
  end

  return controller
end

return ConvoyCacheController
end)()

local TM01B = (function()
local TM01B = {}

local OUTCOME_READY = "READY"
local OUTCOME_FAIL_CONFIGURATION = "FAIL_CONFIGURATION"
local OUTCOME_FAIL_SCRIPT = "FAIL_SCRIPT"

local function join(values)
  if #values == 0 then
    return "none"
  end
  return table.concat(values, ",")
end

local function validateFunction(path, getter, missing)
  local ok, value = pcall(getter)
  if not ok or type(value) ~= "function" then
    missing[#missing + 1] = path
  end
end

local function validateTm01bNativeApis()
  local missing = {}

  validateFunction("timer.scheduleFunction", function()
    return timer and timer.scheduleFunction
  end, missing)
  validateFunction("Group.getByName", function()
    return Group and Group.getByName
  end, missing)

  return #missing == 0, missing
end

local function validateTm01bMooseApis()
  local missing = {}

  validateFunction("GROUP.GetUnits", function()
    return GROUP and GROUP.GetUnits
  end, missing)
  validateFunction("POSITIONABLE.Destroy", function()
    return POSITIONABLE and POSITIONABLE.Destroy
  end, missing)
  validateFunction("SPAWN.InitPositionCoordinate", function()
    return SPAWN and SPAWN.InitPositionCoordinate
  end, missing)
  validateFunction("SPAWN.Spawn", function()
    return SPAWN and SPAWN.Spawn
  end, missing)

  return #missing == 0, missing
end

local function isInteger(value)
  return type(value) == "number" and value >= 0 and value == math.floor(value)
end

local function validateConfiguration(config)
  local missing = {}
  local errors = {}
  local checked = {}

  local function checkGroup(name)
    if checked["group:" .. name] then
      return
    end
    checked["group:" .. name] = true

    local ok, group = pcall(function()
      return GROUP:FindByName(name)
    end)
    if not ok then
      errors[#errors + 1] = name .. ": " .. tostring(group)
    elseif not group then
      missing[#missing + 1] = name
    end
  end

  local function checkZone(name)
    if checked["zone:" .. name] then
      return
    end
    checked["zone:" .. name] = true

    local ok, zone = pcall(function()
      return ZONE:FindByName(name)
    end)
    if not ok then
      errors[#errors + 1] = name .. ": " .. tostring(zone)
    elseif not zone then
      missing[#missing + 1] = name
    end
  end

  local function requireZoneName(name, description)
    if type(name) ~= "string" or name == "" then
      errors[#errors + 1] = description .. " zone name is missing"
      return false
    end
    checkZone(name)
    return true
  end

  checkGroup(config.template.groupName)

  local routeZoneNames = {}
  if requireZoneName(config.zones.start, "global route start") then
    routeZoneNames[config.zones.start] = true
  end
  if requireZoneName(config.zones.target, "global route target") then
    if routeZoneNames[config.zones.target] then
      errors[#errors + 1] = "global route start and target names must differ"
    end
    routeZoneNames[config.zones.target] = true
  end

  if type(config.zones.routeAnchors) ~= "table"
    or #config.zones.routeAnchors ~= 7 then
    errors[#errors + 1] = "TM01B.1 requires exactly seven intermediate global route anchors"
  else
    for _, zoneName in ipairs(config.zones.routeAnchors) do
      if type(zoneName) ~= "string" or zoneName == "" then
        errors[#errors + 1] = "global route anchor name is missing"
      else
        if routeZoneNames[zoneName] then
          errors[#errors + 1] = "global route zone name is duplicated: " .. zoneName
        end
        routeZoneNames[zoneName] = true
        checkZone(zoneName)
      end
    end
  end

  local routeAnchorCount = type(config.zones.routeAnchors) == "table"
    and #config.zones.routeAnchors or 0
  local finalSegmentIndex = routeAnchorCount + 1
  local previousExitSegmentIndex = nil

  if type(config.zones.revealSections) ~= "table"
    or #config.zones.revealSections < 2 then
    errors[#errors + 1] = "at least two reveal sections are required"
  else
    for sectionIndex, section in ipairs(config.zones.revealSections) do
      if type(section.id) ~= "string" or section.id == "" then
        errors[#errors + 1] = "reveal section id is missing"
      end

      if type(section.entry) ~= "string" or section.entry == "" then
        errors[#errors + 1] = "reveal section entry zone is missing"
      else
        if routeZoneNames[section.entry] then
          errors[#errors + 1] = "reveal entry must not reuse a global route zone name: "
            .. section.entry
        end
        checkZone(section.entry)
      end

      if type(section.exit) ~= "string" or section.exit == "" then
        errors[#errors + 1] = "reveal section exit zone is missing"
      else
        if routeZoneNames[section.exit] then
          errors[#errors + 1] = "reveal exit must not reuse a global route zone name: "
            .. section.exit
        end
        if section.exit == section.entry then
          errors[#errors + 1] = "reveal entry and exit zone names must differ: "
            .. tostring(section.id)
        end
        checkZone(section.exit)
      end

      if not isInteger(section.entrySegmentIndex) then
        errors[#errors + 1] = "entry segment index is invalid: "
          .. tostring(section.id)
      elseif section.entrySegmentIndex > finalSegmentIndex then
        errors[#errors + 1] = "entry segment index exceeds the global route: "
          .. tostring(section.id)
      end

      if not isInteger(section.exitSegmentIndex) then
        errors[#errors + 1] = "exit segment index is invalid: "
          .. tostring(section.id)
      elseif section.exitSegmentIndex > finalSegmentIndex then
        errors[#errors + 1] = "exit segment index exceeds the global route: "
          .. tostring(section.id)
      end

      if isInteger(section.entrySegmentIndex)
        and isInteger(section.exitSegmentIndex)
        and section.exitSegmentIndex < section.entrySegmentIndex then
        errors[#errors + 1] = "reveal exit precedes reveal entry on the global route: "
          .. tostring(section.id)
      end

      if previousExitSegmentIndex ~= nil
        and isInteger(section.entrySegmentIndex)
        and section.entrySegmentIndex < previousExitSegmentIndex then
        errors[#errors + 1] = "reveal sections are not ordered on the global route: "
          .. tostring(section.id)
      end

      if sectionIndex == 1 and section.entrySegmentIndex ~= 0 then
        errors[#errors + 1] = "the first reveal section must materialize at segment 0, ZONE_TM01_START_BAGRAM"
      end

      if isInteger(section.exitSegmentIndex) then
        previousExitSegmentIndex = section.exitSegmentIndex
      end
    end
  end

  if config.virtualization.initialSectionIndex ~= 1 then
    errors[#errors + 1] = "initialSectionIndex must be 1 for TM01B.1"
  end
  if type(config.zones.revealSections) == "table"
    and config.virtualization.finalSectionIndex ~= #config.zones.revealSections then
    errors[#errors + 1] = "finalSectionIndex must reference the last reveal section"
  end
  if config.template.expectedVehicleCount ~= 6 then
    errors[#errors + 1] = "TM01B.1 expects exactly six configured vehicle slots"
  end
  if config.virtualization.automaticAdvance ~= false
    or config.virtualization.automaticMaterialization ~= false
    or config.virtualization.automaticDematerialization ~= false then
    errors[#errors + 1] = "TM01B.1 automatic transitions must remain disabled"
  end
  if type(config.virtualization.destroyConfirmationPollSeconds) ~= "number"
    or config.virtualization.destroyConfirmationPollSeconds <= 0 then
    errors[#errors + 1] = "destroy confirmation poll interval must be positive"
  end
  if type(config.virtualization.destroyConfirmationTimeoutSeconds) ~= "number"
    or config.virtualization.destroyConfirmationTimeoutSeconds
      <= config.virtualization.destroyConfirmationPollSeconds then
    errors[#errors + 1] = "destroy confirmation timeout must exceed the poll interval"
  end

  local checkedObjectCount = 0
  for _ in pairs(checked) do
    checkedObjectCount = checkedObjectCount + 1
  end

  return {
    valid = #missing == 0 and #errors == 0,
    missing = missing,
    errors = errors,
    checkedObjectCount = checkedObjectCount,
  }
end

function TM01B.start(dependencies)
  local build = dependencies.build
  local config = dependencies.config
  local state = {
    outcome = OUTCOME_FAIL_SCRIPT,
    detail = "bootstrap not completed",
    checkedObjectCount = 0,
  }

  local nativeValid, missingNativeApis = dependencies.runtimeGuard.validateNative()
  if not nativeValid then
    state.detail = "required native DCS APIs are unavailable"
    dependencies.safeReporter.report(
      "native_api_validation_failed",
      OUTCOME_FAIL_SCRIPT,
      "missing=" .. join(missingNativeApis),
      "[OMW][TM01B]"
    )
    return state
  end

  local logger = dependencies.structuredLogger.new("[OMW][TM01B]")

  local function announce(text)
    trigger.action.outText("[OMW][TM01B] " .. text, 15, false)
  end

  local function setOutcome(outcome, detail)
    state.outcome = outcome
    state.detail = detail
    logger:info("bootstrap_outcome", {
      detail = detail,
      outcome = outcome,
    })
  end

  local function runConfigurationValidation()
    local ok, result = pcall(validateConfiguration, config)
    if not ok then
      setOutcome(OUTCOME_FAIL_SCRIPT, "configuration validation raised an error")
      logger:error("configuration_validation_error", { error = result })
      return false
    end

    state.checkedObjectCount = result.checkedObjectCount
    if #result.errors > 0 then
      setOutcome(OUTCOME_FAIL_SCRIPT, "configuration validation failed")
      logger:error("configuration_lookup_error", {
        checkedObjectCount = result.checkedObjectCount,
        errors = join(result.errors),
      })
      return false
    end
    if not result.valid then
      setOutcome(OUTCOME_FAIL_CONFIGURATION, "required Mission Editor objects are missing")
      logger:error("configuration_invalid", {
        checkedObjectCount = result.checkedObjectCount,
        missing = join(result.missing),
      })
      return false
    end

    logger:info("configuration_valid", {
      checkedObjectCount = result.checkedObjectCount,
      globalRouteStart = config.zones.start,
      globalRouteAnchorCount = #config.zones.routeAnchors,
      globalRoutePointCount = #config.zones.routeAnchors + 2,
      globalRouteTarget = config.zones.target,
      revealSectionCount = #config.zones.revealSections,
      revealZonesAreWaypoints = false,
      revealZonesDetermineSpawn = false,
    })
    setOutcome(OUTCOME_READY, "TM01B global-route and reveal-window configuration completed")
    return true
  end

  local function protectMenuCallback(commandName, callback)
    return function()
      local ok, callbackError = pcall(callback)
      if not ok then
        logger:error("menu_callback_failed", {
          command = commandName,
          error = callbackError,
          outcome = OUTCOME_FAIL_SCRIPT,
        })
        announce("Menu command failed: " .. commandName)
      end
    end
  end

  logger:info("startup", {
    buildTimestamp = build.buildTimestamp,
    configurationVersion = build.configurationVersion,
    dcsVersion = tostring(_G.DCS_VERSION or _G._DCS_VERSION or "unavailable"),
    expectedMooseBuildCommit = build.expectedMooseBuildCommit,
    expectedMooseBuildTimestamp = build.expectedMooseBuildTimestamp,
    expectedMooseCompression = build.expectedMooseCompression,
    expectedMooseFileSha256 = build.expectedMooseFileSha256,
    expectedMooseIncludeFamily = build.expectedMooseIncludeFamily,
    expectedMooseVersion = build.expectedMooseVersion,
    missionTimeSeconds = timer.getTime(),
    mooseVerificationMode = build.mooseVerificationMode,
    stageId = build.stageId,
    testId = build.testId,
  })

  local tm01bNativeValid, missingTm01bNativeApis = validateTm01bNativeApis()
  if not tm01bNativeValid then
    setOutcome(OUTCOME_FAIL_SCRIPT, "required TM01B native APIs are unavailable")
    logger:error("tm01b_native_api_validation_failed", {
      missing = join(missingTm01bNativeApis),
    })
    return state
  end

  logger:info("native_api_validation_passed", {
    baselineNativeApiCount = 3,
    tm01bAdditionalNativeApiCount = 2,
  })

  local baseMooseValid, missingBaseMooseApis = dependencies.runtimeGuard.validateMoose()
  if not baseMooseValid then
    setOutcome(OUTCOME_FAIL_SCRIPT, "required baseline MOOSE APIs are unavailable")
    logger:error("moose_api_validation_failed", {
      missing = join(missingBaseMooseApis),
    })
    return state
  end

  local tm01bMooseValid, missingTm01bMooseApis = validateTm01bMooseApis()
  if not tm01bMooseValid then
    setOutcome(OUTCOME_FAIL_SCRIPT, "required TM01B MOOSE APIs are unavailable")
    logger:error("tm01b_moose_api_validation_failed", {
      missing = join(missingTm01bMooseApis),
    })
    return state
  end

  logger:info("moose_api_validation_passed", {
    baselineMooseApiCount = 13,
    tm01bAdditionalApiCount = 4,
  })

  if not runConfigurationValidation() then
    return state
  end

  local campaignStateOk, campaignStateOrError = pcall(function()
    return dependencies.inMemoryCampaignState.new(config)
  end)
  if not campaignStateOk or type(campaignStateOrError) ~= "table" then
    setOutcome(OUTCOME_FAIL_SCRIPT, "CampaignState initialization failed")
    logger:error("campaign_state_initialization_failed", {
      error = campaignStateOk
        and "InMemoryCampaignState.new returned no table"
        or campaignStateOrError,
    })
    return state
  end

  local campaignState = campaignStateOrError
  local cacheControllerOk, cacheControllerOrError = pcall(function()
    return dependencies.convoyCacheController.new({
      announce = announce,
      campaignState = campaignState,
      config = config,
      getBootstrapOutcome = function()
        return state.outcome
      end,
      logger = logger,
    })
  end)
  if not cacheControllerOk or type(cacheControllerOrError) ~= "table" then
    setOutcome(OUTCOME_FAIL_SCRIPT, "cache controller initialization failed")
    logger:error("cache_controller_initialization_failed", {
      error = cacheControllerOk
        and "ConvoyCacheController.new returned no table"
        or cacheControllerOrError,
    })
    return state
  end

  local cacheController = cacheControllerOrError

  local function showStatus()
    logger:info("status_requested", {
      checkedObjectCount = state.checkedObjectCount,
      detail = state.detail,
      outcome = state.outcome,
    })
    announce("Outcome: " .. state.outcome .. "\nDetail: " .. state.detail)
    cacheController:showStatus()
  end

  local function validateFromMenu()
    runConfigurationValidation()
    showStatus()
  end

  local menuOk, menuOrError = pcall(function()
    local rootMenu = MENU_MISSION:New("OMW Tests")
    local testMenu = MENU_MISSION:New(build.stageId, rootMenu)

    MENU_MISSION_COMMAND:New(
      "Show status",
      testMenu,
      protectMenuCallback("Show status", showStatus)
    )
    MENU_MISSION_COMMAND:New(
      "Validate configuration",
      testMenu,
      protectMenuCallback("Validate configuration", validateFromMenu)
    )
    MENU_MISSION_COMMAND:New(
      "Materialize convoy",
      testMenu,
      protectMenuCallback("Materialize convoy", function()
        cacheController:materialize()
      end)
    )
    MENU_MISSION_COMMAND:New(
      "Start physical route",
      testMenu,
      protectMenuCallback("Start physical route", function()
        cacheController:startPhysicalRoute()
      end)
    )
    MENU_MISSION_COMMAND:New(
      "Dematerialize convoy",
      testMenu,
      protectMenuCallback("Dematerialize convoy", function()
        cacheController:dematerialize()
      end)
    )
    MENU_MISSION_COMMAND:New(
      "Advance virtual convoy",
      testMenu,
      protectMenuCallback("Advance virtual convoy", function()
        cacheController:advanceVirtual()
      end)
    )

    return {
      root = rootMenu,
      test = testMenu,
    }
  end)

  if not menuOk then
    setOutcome(OUTCOME_FAIL_SCRIPT, "F10 menu creation failed")
    logger:error("menu_creation_failed", { error = menuOrError })
    return state
  end

  state.menu = menuOrError
  state.campaignState = campaignState
  state.cacheController = cacheController
  logger:info("campaign_state_ready", {
    entityId = config.scenarioId,
    initialRoutePosition = config.zones.start,
    persistenceEnabled = false,
  })
  logger:info("menu_ready", { path = "OMW Tests / " .. build.stageId })

  return state
end

return TM01B
end)()

local entryOk, entryResult = pcall(function()
  return TM01B.start({
    build = OMWBuild,
    config = TM01BConfig,
    safeReporter = SafeReporter,
    structuredLogger = StructuredLogger,
    runtimeGuard = RuntimeGuard,
    inMemoryCampaignState = InMemoryCampaignState,
    convoyCacheController = ConvoyCacheController,
  })
end)

local TM01BState = entryResult
if not entryOk then
  SafeReporter.report("bootstrap_uncaught_error", "FAIL_SCRIPT", entryResult, "[OMW][TM01B]")
  TM01BState = {
    outcome = "FAIL_SCRIPT",
    detail = "bootstrap raised an uncaught error",
  }
end
